const SETUP_TUTORIAL_REFRESH_MS = 600;
const SETUP_TUTORIAL_FAST_POLL_MS = 400;
const SETUP_TUTORIAL_OCC_STABLE_TICKS = 2;

/** 32 kroků: bílá 1. řada, bílí pěšci, černá 8. řada, černí pěšci. */
